if event == 'booking_new':
    full_booking = requests.get("https://staging.channex.io/api/v1/bookings/%s" % payload_infos.get('booking_id', ''),
        headers={'Content-Type': 'application/json', 'user-api-key': env.company.x_channex_api_key}).json().get('data', {}).get('attributes', {})
