        'name': payload_infos.get('customer_name'),
    })
    so = env['sale.order'].create({
        'partner_id': new_partner.id,
        'is_rental_order': True,
    })
    for room in full_booking.get('rooms', []):
        room_mapping = env['x_channex_mapping'].search(
            [("x_model_type", "=", "room_type"), ('x_id_remote', '=', room.get('room_type_id', ''))], limit=1
        )
        env['sale.order.line'].create({
            'product_id': env['product.product'].browse(room_mapping.x_id_local).id,
            'is_rental': True,
            'order_id': so.id,
        })
    so['rental_start_date'] = full_booking.get('arrival_date')
    so['rental_return_date'] = full_booking.get('departure_date')
    env["x_channex_mapping"].create({
        "x_model_type": "booking",
        "x_id_local": so.id,
        "x_id_remote": payload_infos.get('booking_id', ''),
    })
    try:
        so.action_confirm()
    except Exception as exc:
        pass #Create activity to say there's an error and it should be replaned by someone
elif booking_id := payload_infos.get('booking_id'):
    mapped_so = env["x_channex_mapping"].search([
        ("x_model_type", "=", "booking"),
        ("x_id_remote", "=", booking_id),
    ], limit=1)
    if event == 'booking_modification':
        pass #Here we should modify the booking, can we do that extensively and automatically ? or should we simply create a task to
        #take into account new reservation (could create overlapping issues later)
    elif event == 'booking_cancellation':
        env['sale.order'].browse(mapped_so.x_id_local).action_cancel()

