restrictions_payload = []
availability_payload = []
for line in sending_cron.x_datas_to_send:
    if line.x_operation == 'restrictions':
        restrictions_payload.append(line.x_payload)
    elif line.x_operation == 'availability':
        availability_payload.append(line.x_payload)
if not restrictions_payload.is_empty():
    channex_post("restrictions", {"values": restrictions_payload})
if not availability_payload.is_empty():
    channex_post("availability", {"values": availability_payload})
