sending_cron = env.ref('booking_channex.ir_cron_data_channex_sender')
#Update rate plans
all_price_rules = env['product.pricelist.item'].search([])
for product in env['product.product'].search([('x_is_a_room_offer', '=', True)]):
    main_dates = [datetime.datetime.today().date(), datetime.datetime.today().date() + dateutil.relativedelta.relativedelta(days=500)]
    for price_rule in all_price_rules.filtered(lambda pr: pr.categ_id == env.ref('booking_engine.product_category_6') or product.product_tmpl_id.id in pr.product_tmpl_id.ids):
        main_dates.append(price_rule.date_start.date())
    main_dates.sort()
    mapped_rate_plan = env["x_channex_mapping"].search([
        ("x_model_type", "=", "rate_plan"),
        ("x_id_local", "=", product.product_tmpl_id.id),
    ], limit=1)
    if mapped_rate_plan:
        for i in range(len(main_dates)-1):
            env['x_channex_datas_cron_lines'].create({
                'x_cron_id': sending_cron.id,
                'x_operation': 'restrictions',
                'x_payload': {
                    "property_id": "38149695-d95b-4c80-a7c3-34ce96efc7ba",
                    "rate_plan_id": mapped_rate_plan.x_id_remote,
                    "date_from": datetime.datetime.strftime(main_dates[i],'%Y-%m-%d'),
                    "date_to": datetime.datetime.strftime(main_dates[i+1],'%Y-%m-%d'),
                    "rate": int(product.list_price*100), #To change so it takes into account every price rules
                },
            })
#Update availability - same as rate but using the incoming new model that gives values directly
if not sending_cron.active:
    sending_cron['nextcall'] = datetime.datetime.now() + datetime.timedelta(minutes=1)
    sending_cron['active'] = True

BASE_URL = "https://staging.channex.io/api/v1"
if not env.company.x_channex_api_key:
    raise UserError("Channex API key is missing in company settings.")
header = {
    'Content-Type': 'application/json',
    'user-api-key': env.company.x_channex_api_key
}

def channex_post(endpoint, payload):
    try:
        response = requests.post(f"{BASE_URL}/{endpoint}", headers=header, data=json.dumps(payload), timeout=20)
        response.raise_for_status()
        return response.json()

    except Exception as e:
        raise UserError(f"Channex API error: {str(e)}")

def get_mapping(model, local_id):
    mapping = env['x_channex_mapping'].search([
        ('x_model_type', '=', model),
        ('x_id_local', '=', local_id)
    ], limit=1)

    if not mapping:
        mapping = env['x_channex_mapping'].create({
            "x_model_type": model,
            "x_id_local": local_id,
        })
    return mapping

def create_on_channex(endpoint, payload, mapping, error_msg):
    try:
        data = channex_post(endpoint, payload)
        remote_id = data.get('data', {}).get('attributes', {}).get('id')

        if not remote_id:
            raise UserError(f"{error_msg}: Invalid response from Channex")

        mapping.write({'x_id_remote': remote_id})

    except Exception as e:
        raise UserError(f"{error_msg}: {str(e)}")

# webhook
try:
    resp = requests.get(f"{BASE_URL}/webhooks", headers={'user-api-key': env.company.x_channex_api_key, "Accept":'application/json',}, timeout=20)
    resp.raise_for_status()
    data = resp.json()
except Exception as e:
    raise UserError(f"Error fetching webhooks: {str(e)}")

channex_webhooks = data.get('data', [])
odoo_webhook = env.ref('booking_channex.webhook_get_booking_create_change_or_delete')
existing_webhook = False
for w in channex_webhooks:
    if w.get('attributes', {}).get('callback_url') == odoo_webhook.url:
        existing_webhook = w
        break
webhook_mapping = get_mapping('webhook', odoo_webhook.id)

if existing_webhook:
    webhook_mapping.write({
        'x_id_remote': existing_webhook.get('attributes', {}).get('id')
    })
else:
    payload = {
        "webhook": {
            "callback_url": odoo_webhook.url,
            "event_mask": "booking_new;booking_modification;booking_cancellation",
            "request_params": {},
            "headers": {},
            "is_active": True,
            "is_global": True,
            "send_data": True
        }
    }
    create_on_channex(
        'webhooks',
        payload,
        webhook_mapping,
        "Error creating webhook"
    )

action = {
    'type': 'ir.actions.client',
    'tag': 'display_notification',
    'params': {
        'message': 'WIP: No seeding, No ARI push',
        'type': 'warning',
        'sticky': False,
    }
}

