# GROUP (Parent Company -> Channex Group)
company = env.company
group_mapping = get_mapping('group', company.id)
if not group_mapping.x_id_remote:
    payload = {
        "group": {
            "title": company.name
        }
    }
    create_on_channex(
        "groups",
        payload,
        group_mapping,
        "Error creating group"
    )

# PROPERTIES (Child Companies -> Properties)
companies = company.child_ids or company
for property in companies:
    property_mapping = get_mapping('property', property.id)
    if not property_mapping.x_id_remote:
        payload = {
            "property": {
                "title": property.name,
                "currency": property.currency_id.name,
                "email": property.email or '',
                "phone": property.phone or '',
                "group_id": group_mapping.x_id_remote
            }
        }
        create_on_channex(
            "properties",
            payload,
            property_mapping,
            "Error creating property"
        )

# ROOM TYPES (Product Variants → Room Types)
for property in companies:
    property_mapping = env['x_channex_mapping'].search([('x_model_type', '=', 'property'),('x_id_local', '=', property.id)], limit=1)
    if not property_mapping.x_id_remote:    continue
    property_rooms = env['product.product'].search([('x_is_a_room_offer', '=', True)])
    if company.child_ids:
        property_rooms = property_rooms.filtered(lambda r: r.company_id == property)
    for room in property_rooms:
        room_mapping = get_mapping('room_type', room.id)
        if not room_mapping.x_id_remote:
            payload = {
                "room_type": {
                    "property_id": property_mapping.x_id_remote,
                    "title": room.display_name,
                    "count_of_rooms": 5,
                    "occ_adults": 1, "occ_children": 0, "occ_infants": 0,
                    "default_occupancy": 1
                }
            }
            create_on_channex(
                "room_types",
                payload,
                room_mapping,
                "Error creating room type"
            )

# RATE PLANS (Pricelist → Channex Rate Plan)
for property in companies:
    property_mapping = env['x_channex_mapping'].search([('x_model_type', '=', 'property'),('x_id_local', '=', property.id)], limit=1)
    if not property_mapping.x_id_remote:    continue
    pricelists = env['product.pricelist'].search([('company_id', '=', property.id)])
    if not pricelists:    continue
    property_rooms = env['product.product'].search([('x_is_a_room_offer', '=', True)])
    if company.child_ids:
        property_rooms = property_rooms.filtered(lambda r: r.company_id == property)
    for room in property_rooms:
        room_mapping = get_mapping('room_type', room.id)
        if not room_mapping.x_id_remote:    continue
        for pricelist in pricelists:
            payload = {
                "rate_plan": {
                    "title": f"{room.display_name} - {pricelist.name}",
                    "property_id": property_mapping.x_id_remote,
                    "room_type_id": room_mapping.x_id_remote,
                    "currency": pricelist.currency_id.name,
                    "options": [
                      {
                        "occupancy": 3,
                        "is_primary": True
                      }
                    ],
                }
            }
            try:
                data = channex_post("rate_plans", payload)
                rate_plan_id = data.get('data', {}).get('attributes', {}).get('id', '')
                env['x_channex_mapping'].create({
                    "x_model_type": "rate_plan",
                    "x_id_local": pricelist.id,
                    "x_id_remote": rate_plan_id,
                })
            except Exception as e:
                raise UserError("Channex API error: %s" % str(e))

action = {
